import{_ as a,o as e,c as t,a2 as i}from"./chunks/framework.D9w8F3MR.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md"}'),n={name:"guide/quick-start.md"};function r(l,s,o,p,d,h){return e(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>Get Tierward running in your project in under two minutes.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>Node.js 22 or later</li><li>Claude Code installed and active in your project</li></ul><div class="info custom-block"><p class="custom-block-title">Claude Code-only</p><p>Tierward&#39;s enforcement layer — Stop hook, STOP gates, audit skills — is built on Claude Code primitives (<code>settings.json</code>, <code>pipeline.md</code>, the agent skill system). It does not support Cursor, Copilot, or other AI coding tools. This is a deliberate architectural choice; see <a href="https://github.com/marcoguillermaz/Tierward#claude-code-first-by-design" target="_blank" rel="noreferrer">Claude Code-first, by design</a> in the README for the reasoning.</p></div><h2 id="run-the-wizard" tabindex="-1">Run the wizard <a class="header-anchor" href="#run-the-wizard" aria-label="Permalink to &quot;Run the wizard&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>The wizard detects your project state and asks a few questions: team size, tech stack, which features you have (API, database, frontend, design system). It then scaffolds the right pipeline, rules, and audit skills for your setup.</p><p>Three paths are available:</p><table tabindex="0"><thead><tr><th>Path</th><th>Use when</th></tr></thead><tbody><tr><td><strong>Existing project</strong></td><td>Add structure to a project that already has code</td></tr><tr><td><strong>New project</strong></td><td>Starting from scratch</td></tr><tr><td><strong>From existing docs</strong></td><td>You have a spec or requirements doc; Claude reads it and populates everything</td></tr></tbody></table><p>After the wizard completes, open Claude Code. The scaffold is active immediately, no restart needed.</p><h2 id="what-gets-scaffolded" tabindex="-1">What gets scaffolded <a class="header-anchor" href="#what-gets-scaffolded" aria-label="Permalink to &quot;What gets scaffolded&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>├── CLAUDE.md                    # Project context</span></span>
<span class="line"><span>├── .claude/</span></span>
<span class="line"><span>│   ├── settings.json            # Permissions + Stop hook</span></span>
<span class="line"><span>│   ├── rules/</span></span>
<span class="line"><span>│   │   ├── pipeline.md          # Development workflow</span></span>
<span class="line"><span>│   │   ├── security.md          # Stack-aware security rules</span></span>
<span class="line"><span>│   │   ├── git.md               # Commit format and branch rules</span></span>
<span class="line"><span>│   │   └── output-style.md      # Communication rules</span></span>
<span class="line"><span>│   └── skills/                  # Audit skills (conditional per project)</span></span>
<span class="line"><span>├── .github/</span></span>
<span class="line"><span>│   ├── CODEOWNERS               # Protects .claude/ from unreviewed changes</span></span>
<span class="line"><span>│   └── PULL_REQUEST_TEMPLATE.md</span></span>
<span class="line"><span>└── .pre-commit-config.yaml      # Secret scanning</span></span></code></pre></div><p>The exact files depend on your tier and project flags. Run <code>npx tierward doctor</code> after init to confirm everything is in order.</p><h2 id="validate-your-setup" tabindex="-1">Validate your setup <a class="header-anchor" href="#validate-your-setup" aria-label="Permalink to &quot;Validate your setup&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><p>Doctor runs 29 checks across your scaffold: Stop hook presence, pipeline structure, CODEOWNERS coverage, placeholder residuals, and more. It exits 0 when everything is clean.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --report</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # JSON output (for CI)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ci</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # silent, exits 1 on any failure</span></span></code></pre></div><h2 id="context-builder-optional" tabindex="-1">Context Builder (optional) <a class="header-anchor" href="#context-builder-optional" aria-label="Permalink to &quot;Context Builder (optional)&quot;">​</a></h2><p>If you want the scaffold to come out the same way every time (or want a written record of the decisions), run <code>context</code> before <code>init</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> context</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # produces CONTEXT.md via interview</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # reads CONTEXT.md, no further prompts</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> context</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # one-shot: context then init</span></span></code></pre></div><p><code>CONTEXT.md</code> is a schema-validated file that covers tier, stack, team size, and all project flags. Running <code>init</code> from it bypasses the interactive wizard entirely.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><strong><a href="./tiers.html">Tiers →</a></strong> — which tier fits your team and when to upgrade</li><li><strong><a href="./../skills/">Skills →</a></strong> — full skill library</li><li><strong><a href="./../config/stop-hook.html">Stop hook →</a></strong> — how the enforcement mechanism works</li></ul>`,24)])])}const k=a(n,[["render",r]]);export{u as __pageData,k as default};
